openscad:
$fn = 60;
arm_length = 80; // [40:5:150]
arm_width = 40; // [20:5:80]
thickness = 10; // [5:1:20]
hole_dia = 5; // [3:1:10]
hole_offset = 15; // [8:1:30]

module bracket() {
  difference() {
    union() {
      // horizontal arm
      cube([arm_length, arm_width, thickness]);
      // vertical arm
      cube([thickness, arm_width, arm_length]);
    }
    // hole 1 - far end horizontal
    translate([arm_length - hole_offset, arm_width/2, -1])
      cylinder(h = thickness + 2, d = hole_dia);
    // hole 2 - upper vertical
    translate([-1, arm_width/2, arm_length - hole_offset])
      rotate([0, 90, 0])
        cylinder(h = thickness + 2, d = hole_dia);
    // hole 3 - lower vertical corner
    translate([-1, arm_width/2, hole_offset + thickness])
      rotate([0, 90, 0])
        cylinder(h = thickness + 2, d = hole_dia);
  }
}

color("gray") bracket();
